mapper.select:
SELECT grp_cd_oid, grp_cd, grp_cd_nm, grp_cd_expln, use_yn, reg_id, reg_dt, mdfcn_id, mdfcn_dt FROM ${schema}.grp_cd
AND ( grp_cd LIKE CONCAT('%', #{keyword}, '%') OR grp_cd_nm LIKE CONCAT('%', #{keyword}, '%') )
AND use_yn = #{useYn}

SELECT cd_oid, grp_cd_oid, cd_val, cd_nm, up_cd_val, cd_expln, cd_seq, use_yn, atrb1, atrb2, atrb3, atrb4, atrb5, reg_id, reg_dt, mdfcn_id, mdfcn_dt FROM ${schema}.cd
AND grp_cd_oid = #{grpCdOid}
AND use_yn = 'Y'
